      title: 'бһҮбҹҶбһ–бһјбһҖбһ‘бһё бҹЈ вҖ” бһ…бҹҶбһҺбһ„бһҮбһҫбһ„',
      content: `
        <p>бһҹбһјбһҳбһ”бһ“бҹ’бһҗбҹӮбһҳбһҒбҹ’бһӣбһ№бһҳбһҹбһ¶бһҡбһҮбҹҶбһ–бһјбһҖбһ‘бһёбҹЈбһ“бҹ…бһ‘бһёбһ“бҹҒбҹҮбҹ”</p>
      `
    },
  ])
  
  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  // END EDIT SECTION
  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  
  const STORAGE_KEY = 'novel-reader-state'
  
  const isDark = ref(false)
  const fontSize = ref(18)
  const lineHeight = ref(2.0)
  const maxWidth = ref(720)
  const currentChapter = ref(0)
  const bookmarks = ref([])
  const showToc = ref(false)
  const showSettings = ref(false)
  const showScrollTop = ref(false)
  const readingArea = ref(null)
  
  const widthOptions = [
    { label: 'бһҸбһјбһ…', value: 580 },
    { label: 'бһҳбһ’бҹ’бһҷбһҳ', value: 720 },
    { label: 'бһ’бҹҶ', value: 900 },
  ]
  
  const contentStyle = computed(() => ({
    fontSize: fontSize.value + 'px',
    lineHeight: lineHeight.value,
    maxWidth: maxWidth.value + 'px',
  }))
  
  const progressPercent = computed(() => {
    if (chapters.value.length <= 1) return 100
    return Math.round(((currentChapter.value) / (chapters.value.length - 1)) * 100)
  })
  
  const isCurrentBookmarked = computed(() => bookmarks.value.includes(currentChapter.value))
  
  function changeFontSize(delta) {
    const next = fontSize.value + delta
    if (next >= 14 && next <= 28) fontSize.value = next
  }
  
  function toggleBookmark() {
    const idx = bookmarks.value.indexOf(currentChapter.value)
    if (idx === -1) {
      bookmarks.value.push(currentChapter.value)
    } else {
      bookmarks.value.splice(idx, 1)
    }
    saveState()
  }
  
  function goToChapter(idx) {
    if (idx < 0 || idx >= chapters.value.length) return
    currentChapter.value = idx
    showToc.value = false
    scrollToTop()
    saveState()
  }
  
  function scrollToTop() {
    window.scrollTo({ top: 0, behavior: 'smooth' })
  }
  
  function handleScroll() {
    showScrollTop.value = window.scrollY > 400
  }
  
  function handleKeydown(e) {
    if (e.key === 'ArrowLeft') goToChapter(currentChapter.value - 1)
    if (e.key === 'ArrowRight') goToChapter(currentChapter.value + 1)
  }
  
  function saveState() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify({
        currentChapter: currentChapter.value,
        bookmarks: bookmarks.value,
        fontSize: fontSize.value,
        lineHeight: lineHeight.value,
        maxWidth: maxWidth.value,
        isDark: isDark.value,
      }))
    } catch {}
  }
  
  function loadState() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY)
      if (raw) {
        const data = JSON.parse(raw)
        currentChapter.value = data.currentChapter ?? 0
        bookmarks.value = data.bookmarks ?? []
        fontSize.value = data.fontSize ?? 18
        lineHeight.value = data.lineHeight ?? 2.0
        maxWidth.value = data.maxWidth ?? 720
        isDark.value = data.isDark ?? false
      }
    } catch {}
  }
  
  watch([isDark, fontSize, lineHeight, maxWidth], () => saveState())
  
  onMounted(() => {
    loadState()
    window.addEventListener('scroll', handleScroll)
    window.addEventListener('keydown', handleKeydown)
  })
  
  onUnmounted(() => {
    window.removeEventListener('scroll', handleScroll)
    window.removeEventListener('keydown', handleKeydown)
  })
